class Solution:
    def buildArray(self, target, n):
        ops = []
        t_set = set(target)
        ti = 0
        for num in range(1, n + 1):
            if ti == len(target):
                break
            ops.append('Push')
            if num != target[ti]:
                ops.append('Pop')
            else:
                ti += 1
        return ops

