var buildArray = function(target, n) {
    const ops = [];
    let ti = 0;
    for (let num = 1; num <= n && ti < target.length; num++) {
        ops.push('Push');
        if (num !== target[ti]) {
            ops.push('Pop');
        } else {
            ti++;
        }
    }
    return ops;
};
